import React from 'react'
import useSplitPaymentStore from '../useSplitPaymentStore'
import useData, { getTotalAmount } from '../useData'

const TITLE = {
    TEXT: 'Split Payments',
    DESC: 'Split your Payments using our tool!'
}
function Title() {
    const { data, loading, error } = useData(getTotalAmount)
    const { totalAmount, setTotalAmount } = useSplitPaymentStore((s) => s)
    if (loading) {
        return <>Loading...</>
    }
    if (error.message) {
        return <>{error.message}</>
    }
    if (data) {
        return <div className='flex flex-col justify-center items-center'>
            <div className='p-2 text-4xl text-blue-600 dark:text-sky-400'>{TITLE.TEXT}</div>
            <div className='p-2 text-2xl text-blue-600 dark:text-sky-400'>{TITLE.DESC}</div>
            <div className='p-2 text-2xl text-blue-600 dark:text-sky-400'>{`Total Amount: Rs ${totalAmount}`}</div>
        </div>
    }
}

export default Title
